// Detailed Medieval Watchtower with customizable parts
const { Manifold } = api;

// 1. Tower Body & Base
const body = Manifold.cylinder(60, 15, 12.5);

// 2. Buttresses
const baseBox = Manifold.cube([8, 6, 1], true).translate([13, 0, 0.5]);
const topBox = Manifold.cube([3, 1.5, 1], true).translate([11, 0, 20.5]);
const buttressTemplate = Manifold.hull([baseBox, topBox]);
let buttresses = buttressTemplate;
for (let i = 1; i < 4; i++) {
  buttresses = buttresses.add(buttressTemplate.rotate([0, 0, i * 90]));
}

// 3. Corbels (stone supports under the battlements)
const corbelTemplate = Manifold.cube([1.5, 1.2, 4], true).translate([12.4, 0, 58]);
let corbels = corbelTemplate;
for (let i = 1; i < 8; i++) {
  corbels = corbels.add(corbelTemplate.rotate([0, 0, i * 45]));
}

// 4. Battlements Rim & Parapet
const topRim = Manifold.cylinder(5, 12.5, 15.5).translate([0, 0, 60]);
const parapet = Manifold.cylinder(6, 15.5, 15.5).translate([0, 0, 65]);
const platformHollow = Manifold.cylinder(10, 13.5, 13.5).translate([0, 0, 65.5]);

let towerStone = body.add(buttresses).add(corbels).add(topRim).add(parapet).subtract(platformHollow);

// 5. Merlon Cutters (slotted battlements)
let cutters = Manifold.cube([5, 40, 3], true).translate([0, 0, 69.5]);
for (let i = 1; i < 4; i++) {
  cutters = cutters.add(Manifold.cube([5, 40, 3], true).translate([0, 0, 69.5]).rotate([0, 0, i * 45]));
}
towerStone = towerStone.subtract(cutters);

// 6. Doorway Cutter
const archBox = Manifold.cube([6, 10, 10], true).translate([0, 0, 5]);
const archTop = Manifold.cylinder(10, 3, 3).rotate([90, 0, 0]).translate([0, 5, 10]);
const doorwayCutter = archBox.add(archTop).translate([0, -13, 1]);
towerStone = towerStone.subtract(doorwayCutter);

// Door Insert (Wooden Door)
const doorBox = Manifold.cube([5.8, 1, 9.8], true).translate([0, 0, 4.9]);
const doorTop = Manifold.cylinder(1, 2.9, 2.9).rotate([90, 0, 0]).translate([0, 0.5, 9.8]);
const doorInsert = doorBox.add(doorTop).translate([0, -12, 1]);

// Iron Bands for Door
const band1 = Manifold.cube([5.4, 0.3, 0.6], true).translate([0, -11.4, 4]);
const band2 = Manifold.cube([5.4, 0.3, 0.6], true).translate([0, -11.4, 8]);
const doorBands = band1.add(band2);

// 7. Arrow Slit Cutters (Windows)
let windowCutters = Manifold.cube([1.2, 10, 6], true).translate([0, 13, 35]);
for (let i = 1; i < 4; i++) {
  windowCutters = windowCutters.add(Manifold.cube([1.2, 10, 6], true).translate([0, 13, 35]).rotate([0, 0, i * 90]));
}
towerStone = towerStone.subtract(windowCutters);

// 8. Central Turret & Roof (with overlaps)
const turret = Manifold.cylinder(13.5, 5.5, 5).translate([0, 0, 64]);
const roof = Manifold.cylinder(10, 6.2, 0).translate([0, 0, 76.5]);

// 9. Flagpole & Flag
const flagpole = Manifold.cylinder(14, 0.4, 0.4).translate([0, 0, 85]);
const flag = Manifold.cube([0.2, 6, 4], true).translate([0, 2.8, 96]);

// Union with Labels for rich coloring
const stoneLabeled = api.label(towerStone.add(turret), 'stone');
const doorLabeled = api.label(doorInsert, 'door');
const bandsLabeled = api.label(doorBands, 'iron');
const roofLabeled = api.label(roof, 'roof');
const poleLabeled = api.label(flagpole, 'pole');
const flagLabeled = api.label(flag, 'flag');

const finalTower = stoneLabeled
  .add(doorLabeled)
  .add(bandsLabeled)
  .add(roofLabeled)
  .add(poleLabeled)
  .add(flagLabeled);

return finalTower;

